import React from 'react';

import './styles/app.scss';

import { authService } from 'Services/authService';

import AppRoutes from './routes/AppRoutes';
import SentryErrorBoundary from './errorBoundery/SentryErrorBoundary';
import ConfigProviders from './ConfigProviders';
import NotificationFeature from './notification/NotificationFeature';

authService.initialize();

const App = () => (
  <SentryErrorBoundary>
    <ConfigProviders>
      <NotificationFeature />

      <AppRoutes />
    </ConfigProviders>
  </SentryErrorBoundary>
);

export default App;

